// Audit + Soft Delete Interceptor
public class AuditInterceptor(ICurrentUserService currentUser) : SaveChangesInterceptor
{
    public override InterceptionResult<int> SavingChanges(
        DbContextEventData data, InterceptionResult<int> result)
    {
        var ctx = data.Context!;
        var now = DateTimeOffset.UtcNow;

        foreach (var entry in ctx.ChangeTracker.Entries<BaseEntity>())
        {
            switch (entry.State)
            {
                case EntityState.Added:
                    entry.Entity.CreatedAt = now;
                    entry.Entity.CreatedBy = currentUser.UserId;
                    break;
                case EntityState.Modified:
                    entry.Entity.UpdatedAt = now;
                    entry.Entity.UpdatedBy = currentUser.UserId;
                    break;
                case EntityState.Deleted when entry.Entity is ISoftDelete sd:
                    entry.State = EntityState.Modified; // thay vì DELETE
                    sd.IsDeleted = true;
                    sd.DeletedAt = now;
                    break;
            }
        }
        return result;
    }
}

// Registration
protected override void OnConfiguring(DbContextOptionsBuilder opt) =>
    opt.AddInterceptors(new AuditInterceptor(_currentUser));

// Global Query Filter cho soft delete (tốt hơn interceptor cho query)
protected override void OnModelCreating(ModelBuilder model)
{
    foreach (var entityType in model.Model.GetEntityTypes()
        .Where(e => typeof(ISoftDelete).IsAssignableFrom(e.ClrType)))
    {
        model.Entity(entityType.ClrType)
            .HasQueryFilter(e => !EF.Property<bool>(e, "IsDeleted"));
    }
}
